def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Helper function to convert predicate to natural language phrase
    def get_phrase(predicate, obj, subject=None):
        if predicate == "alternativeName":
            return f"also known as {obj}"
        elif predicate == "creator":
            return f"created by {obj}"
        elif predicate == "fullName":
            return f"whose full name is {obj}"
        elif predicate == "foundedBy":
            return f"founded by {obj}"
        elif predicate == "keyPerson":
            return f"with key person {obj}"
        elif predicate == "city":
            return f"located in {obj}"
        elif predicate == "product":
            return f"produces {obj}"
        elif predicate == "lastAired":
            return f"last aired on {obj}"
        elif predicate == "starring":
            return f"starring {obj}"
        elif predicate == "firstAppearanceInFilm":
            return f"first appeared in {obj}"
        elif predicate == "voice":
            return f"voiced by {obj}"
        elif predicate == "distributor":
            return f"distributed by {obj}"
        elif predicate == "birthPlace":
            return f"born in {obj}"
        elif predicate == "nationality":
            # Handle nationality more carefully - keep original form
            return f"of {obj}"
        elif predicate == "award":
            return f"received the {obj}"
        elif predicate == "broadcastedBy":
            return f"broadcast by {obj}"
        elif predicate == "firstAired":
            return f"first aired on {obj}"
        elif predicate == "series":
            return f"part of {obj}"
        elif predicate == "child":
            return f"with child {obj}"
        else:
            return f"{predicate}: {obj}"

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find main subject (appears most frequently as subject)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))

    # Build sentence structure
    sentence_parts = []
    main_parts = []
    related_parts = []

    # Process main subject's triples
    for t in subject_triples[main_subject]:
        phrase = get_phrase(t.predicate, t.object, main_subject)
        main_parts.append((t.predicate, phrase))

    # Find and process related subjects
    for subject, triples_list in subject_triples.items():
        if subject != main_subject:
            # Check if this subject is referenced in main subject's triples
            for t in subject_triples[main_subject]:
                if t.object == subject:
                    # This subject is connected to main subject via one of its properties
                    for rt in triples_list:
                        phrase = get_phrase(rt.predicate, rt.object, subject)
                        # Determine appropriate relative pronoun based on predicate
                        if rt.predicate in ["birthPlace", "nationality", "city"]:
                            related_parts.append(f"who was {phrase}")
                        else:
                            related_parts.append(f"who is {phrase}")
                    break

    # Build the complete sentence
    if len(main_parts) == 1 and not related_parts:
        # Single triple case
        pred, phrase = main_parts[0]
        if pred == "creator":
            return f"{main_subject} was created by {subject_triples[main_subject][0].object}."
        elif pred == "birthPlace":
            return f"{main_subject} was born in {subject_triples[main_subject][0].object}."
        elif pred == "nationality":
            obj = subject_triples[main_subject][0].object
            nat = obj.rstrip('s') if obj.endswith('s') else obj
            return f"{main_subject} is a {nat} national."
        else:
            return f"{main_subject} {phrase}."
    else:
        # Multiple triples - create a complex sentence
        result = main_subject

        # Add main subject's properties
        for i, (pred, phrase) in enumerate(main_parts):
            if i == 0:
                if pred == "creator":
                    result += f" was created by {subject_triples[main_subject][0].object}"
                elif pred == "birthPlace":
                    result += f" was born in {subject_triples[main_subject][0].object}"
                elif pred == "nationality":
                    obj = subject_triples[main_subject][0].object
                    nat = obj.rstrip('s') if obj.endswith('s') else obj
                    result += f" is a {nat} national"
                elif pred == "starring":
                    result += f" starring {subject_triples[main_subject][0].object}"
                elif pred == "broadcastedBy":
                    result += f" broadcast by {subject_triples[main_subject][0].object}"
                else:
                    result += f" {phrase}"
            else:
                result += f", {phrase}"

        # Add related parts
        if related_parts:
            result += ", " + ", ".join(related_parts)

        return result + "."

